const BY_DAY = new Map(DAYS.map((d) => [d.day, d]));

// Platform contract: which day indexes exist, and how to load one.
export function dayIndexes() {
  return DAYS.map((d) => d.day);
}

export function loadDay(idx) {
  return BY_DAY.get(idx) || null;
}
